{"content": "     1|#!/usr/bin/env node
     2|// Pre-build script: copies all @ai-whisperers/* file: linked packages to node_modules
     3|// Turbopack doesn't resolve file: symlinks properly, so we copy the dist instead.
     4|const fs = require('fs')
     5|const path = require('path')
     6|
     7|const pkgJson = JSON.parse(fs.readFileSync('package.json', 'utf8'))
     8|const deps = { ...pkgJson.dependencies, ...pkgJson.devDependencies }
     9|
    10|const aiDeps = Object.entries(deps).filter(
    11|  ([name, link]) => name.startsWith('@ai-whisperers/') && typeof link === 'string' && link.startsWith('file:')
    12|)
    13|
    14|if (aiDeps.length === 0) {
    15|  console.log('copy-ai-packages: no @ai-whisperers file: dependencies found')
    16|  process.exit(0)
    17|}
    18|
    19|const BASE_DIR = path.resolve('node_modules/@ai-whisperers')
    20|if (!fs.existsSync(BASE_DIR)) {
    21|  console.log('copy-ai-packages: node_modules/@ai-whisperers does not exist. Run npm install first.')
    22|  process.exit(0)
    23|}
    24|
    25|function copyRecursive(src, dest) {
    26|  if (!fs.existsSync(dest)) fs.mkdirSync(dest, { recursive: true })
    27|  const entries = fs.readdirSync(src, { withFileTypes: true })
    28|  for (const entry of entries) {
    29|    const s = path.join(src, entry.name)
    30|    const d = path.join(dest, entry.name)
    31|    if (entry.isDirectory()) {
    32|      copyRecursive(s, d)
    33|    } else {
    34|      fs.copyFileSync(s, d)
    35|    }
    36|  }
    37|}
    38|
    39|let count = 0
    40|for (const [name, link] of aiDeps) {
    41|  const pkgName = name.replace('@ai-whisperers/', '')
    42|  const targetPath = path.join(BASE_DIR, pkgName)
    43|
    44|  if (!fs.existsSync(targetPath)) {
    45|    console.log(`copy-ai-packages: ${name} does not exist in node_modules, skipping`)
    46|    continue
    47|  }
    48|
    49|  let stat
    50|  try {
    51|    stat = fs.lstatSync(targetPath)
    52|  } catch {
    53|    console.log(`copy-ai-packages: ${name} cannot stat, skipping`)
    54|    continue
    55|  }
    56|
    57|  if (!stat.isSymbolicLink()) {
    58|    console.log(`copy-ai-packages: ${name} already a real directory, skipping`)
    59|    continue
    60|  }
    61|
    62|  let realPath
    63|  try {
    64|    realPath = fs.readlinkSync(targetPath)
    65|  } catch {
    66|    console.log(`copy-ai-packages: ${name} cannot read link, skipping`)
    67|    continue
    68|  }
    69|
    70|  const absRealPath = path.resolve(path.dirname(targetPath), realPath)
    71|
    72|  if (!fs.existsSync(absRealPath)) {
    73|    // file: dependency points outside the Docker build context
    74|    // Try to use npm link or copy from node_modules if pre-installed
    75|    console.log(`copy-ai-packages: ${name} linked path ${absRealPath} not found (outside build context?)`)
    76|    // Write a placeholder so later npm steps don't fail
    77|    fs.writeFileSync(path.join(targetPath, '../.ai-packages-stub'), `${name}\n`)
    78|    continue
    79|  }
    80|
    81|  fs.rmSync(targetPath, { recursive: true, force: true })
    82|  copyRecursive(absRealPath, targetPath)
    83|  count++
    84|  console.log(`copy-ai-packages: copied ${name} (${absRealPath} → ${targetPath})`)
    85|}
    86|
    87|console.log(`copy-ai-packages: done (${count} package${count !== 1 ? 's' : ''} copied)`)
